<template>
  <div class="workflow-editor-container">
    <div class="page-header">
      <h1>{{ isEdit ? `编辑工作流 - ${workflow.name}` : '创建新工作流' }}</h1>
      <div class="header-actions">
        <el-button @click="$router.push('/workflow')">
          <el-icon><back /></el-icon> 返回
        </el-button>
        <el-button type="primary" @click="saveWorkflow" :loading="isLoading">
          <el-icon><circle-check /></el-icon> 保存工作流
        </el-button>
      </div>
    </div>
    
    <el-card class="editor-card" v-loading="isLoading">
      <el-tabs v-model="activeTab" class="editor-tabs">
        <el-tab-pane label="可视化编辑器" name="editor">
          <div class="step-toolbar">
            <el-button-group>
              <el-button type="success" @click="addNode('a2a_client')">
                <el-icon><connection /></el-icon> 添加A2A步骤
              </el-button>
              <el-button type="primary" @click="addNode('condition')">
                <el-icon><switch /></el-icon> 添加条件步骤
              </el-button>
              <el-button type="warning" @click="addNode('loop')">
                <el-icon><refresh-right /></el-icon> 添加循环步骤
              </el-button>
              <el-button type="danger" @click="addNode('transform')">
                <el-icon><refresh /></el-icon> 添加转换步骤
              </el-button>
            </el-button-group>
          </div>
          
          <div class="workflow-canvas">
            <div v-if="workflow.steps.length === 0" class="canvas-empty">
              <el-empty description="点击上方按钮添加工作流步骤">
                <el-button type="primary" @click="addNode('a2a_client')">
                  添加第一个步骤
                </el-button>
              </el-empty>
            </div>
            
            <div v-else class="workflow-nodes">
              <workflow-node
                v-for="(step, index) in workflow.steps"
                :key="step.id"
                :step="step"
                :index="index"
                @edit="editNode"
                @remove="confirmRemoveNode"
                @move-up="moveNodeUp(index)"
                @move-down="moveNodeDown(index)"
              />
            </div>
          </div>
        </el-tab-pane>
        
        <el-tab-pane label="JSON编辑器" name="json">
          <p class="text-muted">您可以直接编辑工作流定义的JSON结构。注意：修改此处将覆盖可视化编辑器中的内容。</p>
          <el-input
            v-model="jsonDefinition"
            type="textarea"
            :rows="20"
            placeholder="工作流定义 (JSON格式)"
            class="json-editor"
          />
          <div class="json-actions">
            <el-button type="primary" @click="updateFromJson">
              应用JSON更改
            </el-button>
            <el-button type="warning" @click="formatJson">
              格式化JSON
            </el-button>
          </div>
        </el-tab-pane>
        
        <el-tab-pane label="工作流设置" name="settings">
          <el-form 
            ref="settingsForm" 
            :model="workflow" 
            :rules="settingsRules" 
            label-position="top"
          >
            <el-form-item label="工作流名称" prop="name">
              <el-input v-model="workflow.name" placeholder="请输入工作流名称" />
            </el-form-item>
            
            <el-form-item label="描述" prop="description">
              <el-input 
                v-model="workflow.description" 
                type="textarea" 
                :rows="3" 
                placeholder="请输入工作流描述"
              />
            </el-form-item>
            
            <el-form-item label="工作流类型" prop="workflow_type">
              <el-select v-model="workflow.workflow_type" placeholder="请选择工作流类型" class="full-width">
                <el-option label="企业工作流" value="enterprise" />
                <el-option label="主播工作流" value="streamer" />
                <el-option label="通用工作流" value="general" />
              </el-select>
            </el-form-item>
            
            <el-form-item label="标签" prop="tags">
              <el-select
                v-model="workflow.tags"
                multiple
                filterable
                allow-create
                default-first-option
                placeholder="请选择或创建标签"
                class="full-width"
              >
                <el-option
                  v-for="tag in availableTags"
                  :key="tag"
                  :label="tag"
                  :value="tag"
                />
              </el-select>
              <div class="help-text">标签可用于分类和筛选工作流</div>
            </el-form-item>
            
            <el-form-item>
              <el-checkbox v-model="workflow.is_public">公开此工作流（其他用户可见并使用）</el-checkbox>
            </el-form-item>
          </el-form>
        </el-tab-pane>
        
        <el-tab-pane label="参数定义" name="parameters">
          <p class="text-muted">定义执行此工作流时需要的输入参数</p>
          
          <div class="parameters-header">
            <el-button type="primary" size="small" @click="addParameter">
              <el-icon><plus /></el-icon> 添加参数
            </el-button>
          </div>
          
          <el-empty v-if="!workflowParameters.length" description="暂无参数定义">
            <el-button type="primary" @click="addParameter">添加第一个参数</el-button>
          </el-empty>
          
          <el-table v-else :data="workflowParameters" border stripe style="width: 100%">
            <el-table-column label="参数名称" prop="name" width="180">
              <template #default="scope">
                <el-input v-model="scope.row.name" placeholder="参数名称" />
              </template>
            </el-table-column>
            
            <el-table-column label="参数键" prop="key" width="150">
              <template #default="scope">
                <el-input v-model="scope.row.key" placeholder="参数键 (变量名)" />
              </template>
            </el-table-column>
            
            <el-table-column label="类型" prop="type" width="120">
              <template #default="scope">
                <el-select v-model="scope.row.type" placeholder="参数类型" class="full-width">
                  <el-option label="字符串" value="string" />
                  <el-option label="数字" value="number" />
                  <el-option label="布尔值" value="boolean" />
                  <el-option label="JSON对象" value="object" />
                </el-select>
              </template>
            </el-table-column>
            
            <el-table-column label="必填" prop="required" width="80" align="center">
              <template #default="scope">
                <el-checkbox v-model="scope.row.required" />
              </template>
            </el-table-column>
            
            <el-table-column label="默认值" prop="defaultValue">
              <template #default="scope">
                <el-input 
                  v-if="scope.row.type === 'string'" 
                  v-model="scope.row.defaultValue" 
                  placeholder="默认值" 
                />
                <el-input-number 
                  v-else-if="scope.row.type === 'number'" 
                  v-model="scope.row.defaultValue" 
                  placeholder="0" 
                  class="full-width"
                />
                <el-switch 
                  v-else-if="scope.row.type === 'boolean'" 
                  v-model="scope.row.defaultValue"
                />
                <el-input 
                  v-else-if="scope.row.type === 'object'" 
                  v-model="scope.row.defaultValueStr" 
                  placeholder="{}" 
                  @change="updateObjectDefault(scope.row)"
                />
              </template>
            </el-table-column>
            
            <el-table-column label="描述" prop="description">
              <template #default="scope">
                <el-input v-model="scope.row.description" placeholder="参数描述" />
              </template>
            </el-table-column>
            
            <el-table-column label="操作" width="100" fixed="right">
              <template #default="scope">
                <el-button 
                  size="small" 
                  type="danger" 
                  circle
                  @click="removeParameter(scope.$index)"
                >
                  <el-icon><delete /></el-icon>
                </el-button>
              </template>
            </el-table-column>
          </el-table>
        </el-tab-pane>
      </el-tabs>
    </el-card>
    
    <!-- 步骤编辑对话框 -->
    <workflow-node-edit
      v-model:visible="nodeEditVisible"
      :node="currentNode"
      @save="saveNode"
    />
    
    <!-- 删除确认对话框 -->
    <el-dialog
      v-model="removeDialogVisible"
      title="确认删除"
      width="30%"
    >
      <span>确定要删除此步骤吗？此操作不可撤销。</span>
      <template #footer>
        <span class="dialog-footer">
          <el-button @click="removeDialogVisible = false">取消</el-button>
          <el-button type="danger" @click="removeNode">确认删除</el-button>
        </span>
      </template>
    </el-dialog>
  </div>
</template>

<script>
import { ref, reactive, computed, watch, onMounted } from 'vue'
import { useRouter, useRoute } from 'vue-router'
import { useWorkflowStore } from '@/store/workflow'
import { ElMessage } from 'element-plus'
import { v4 as uuidv4 } from 'uuid'
import {
  Back,
  CircleCheck,
  Connection,
  Switch,
  RefreshRight,
  Refresh,
  Plus,
  Delete
} from '@element-plus/icons-vue'
import WorkflowNode from '@/components/workflow/WorkflowNode.vue'
import WorkflowNodeEdit from '@/components/workflow/WorkflowNodeEdit.vue'

export default {
  name: 'WorkflowEditor',
  components: {
    Back,
    CircleCheck,
    Connection,
    Switch,
    RefreshRight,
    Refresh,
    Plus,
    Delete,
    WorkflowNode,
    WorkflowNodeEdit
  },
  setup() {
    const router = useRouter()
    const route = useRoute()
    const workflowStore = useWorkflowStore()
    const settingsForm = ref(null)
    
    // 状态
    const activeTab = ref('editor')
    const jsonDefinition = ref('{}')
    const nodeEditVisible = ref(false)
    const currentNode = ref(null)
    const removeDialogVisible = ref(false)
    const nodeToRemove = ref(null)
    
    // 工作流数据
    const workflow = reactive({
      id: null,
      name: '',
      description: '',
      workflow_type: 'general',
      is_public: false,
      tags: [],
      steps: []
    })
    
    // 工作流参数
    const workflowParameters = ref([])
    
    // 表单校验规则
    const settingsRules = {
      name: [
        { required: true, message: '请输入工作流名称', trigger: 'blur' }
      ],
      workflow_type: [
        { required: true, message: '请选择工作流类型', trigger: 'change' }
      ]
    }
    
    // 是否是编辑模式
    const isEdit = computed(() => !!route.params.id)
    const isLoading = computed(() => workflowStore.isLoading)
    
    // 获取所有可用标签
    const availableTags = computed(() => {
      const tags = new Set()
      workflowStore.workflows.forEach(wf => {
        if (wf.tags && Array.isArray(wf.tags)) {
          wf.tags.forEach(tag => tags.add(tag))
        }
      })
      return Array.from(tags)
    })
    
    // 当JSON定义更改时更新工作流
    const updateFromJson = () => {
      try {
        const parsed = JSON.parse(jsonDefinition.value)
        
        // 更新工作流的steps属性
        if (parsed && typeof parsed === 'object') {
          if (Array.isArray(parsed.steps)) {
            workflow.steps = parsed.steps
          } else if (parsed.steps === undefined) {
            workflow.steps = []
          }
          
          // 更新参数定义
          if (Array.isArray(parsed.parameters)) {
            workflowParameters.value = parsed.parameters.map(param => {
              // 确保对象类型的默认值有字符串表示
              if (param.type === 'object' && param.defaultValue) {
                return {
                  ...param,
                  defaultValueStr: typeof param.defaultValue === 'string' 
                    ? param.defaultValue 
                    : JSON.stringify(param.defaultValue)
                }
              }
              return param
            })
          }
        }
        
        ElMessage.success('JSON已更新')
      } catch (error) {
        ElMessage.error('无效的JSON格式: ' + error.message)
      }
    }
    
    // 格式化JSON
    const formatJson = () => {
      try {
        const parsed = JSON.parse(jsonDefinition.value)
        jsonDefinition.value = JSON.stringify(parsed, null, 2)
      } catch (error) {
        ElMessage.error('无效的JSON格式: ' + error.message)
      }
    }
    
    // 添加节点
    const addNode = (type) => {
      const newNode = {
        id: uuidv4(),
        type: type,
        name: getDefaultNodeName(type),
        config: getDefaultNodeConfig(type)
      }
      
      workflow.steps.push(newNode)
      editNode(newNode)
    }
    
    // 编辑节点
    const editNode = (node) => {
      currentNode.value = node
      nodeEditVisible.value = true
    }
    
    // 保存节点
    const saveNode = (node) => {
      const index = workflow.steps.findIndex(step => step.id === node.id)
      if (index !== -1) {
        workflow.steps[index] = { ...node }
      }
      nodeEditVisible.value = false
      
      // 更新JSON
      updateJsonFromWorkflow()
    }
    
    // 确认删除节点
    const confirmRemoveNode = (node) => {
      nodeToRemove.value = node
      removeDialogVisible.value = true
    }
    
    // 删除节点
    const removeNode = () => {
      if (!nodeToRemove.value) return
      
      const index = workflow.steps.findIndex(step => step.id === nodeToRemove.value.id)
      if (index !== -1) {
        workflow.steps.splice(index, 1)
      }
      
      removeDialogVisible.value = false
      nodeToRemove.value = null
      
      // 更新JSON
      updateJsonFromWorkflow()
    }
    
    // 上移节点
    const moveNodeUp = (index) => {
      if (index <= 0) return
      
      const temp = workflow.steps[index]
      workflow.steps[index] = workflow.steps[index - 1]
      workflow.steps[index - 1] = temp
      
      // 更新JSON
      updateJsonFromWorkflow()
    }
    
    // 下移节点
    const moveNodeDown = (index) => {
      if (index >= workflow.steps.length - 1) return
      
      const temp = workflow.steps[index]
      workflow.steps[index] = workflow.steps[index + 1]
      workflow.steps[index + 1] = temp
      
      // 更新JSON
      updateJsonFromWorkflow()
    }
    
    // 根据工作流更新JSON
    const updateJsonFromWorkflow = () => {
      const workflowData = {
        steps: workflow.steps,
        parameters: workflowParameters.value.map(param => {
          // 对于对象类型，尝试解析字符串为JSON
          if (param.type === 'object' && param.defaultValueStr) {
            try {
              const defaultValue = JSON.parse(param.defaultValueStr)
              return { ...param, defaultValue }
            } catch (e) {
              // 如果解析失败，使用空对象作为默认值
              return { ...param, defaultValue: {} }
            }
          }
          return param
        })
      }
      jsonDefinition.value = JSON.stringify(workflowData, null, 2)
    }
    
    // 更新对象类型默认值
    const updateObjectDefault = (parameter) => {
      try {
        parameter.defaultValue = JSON.parse(parameter.defaultValueStr)
      } catch (e) {
        ElMessage.warning('无效的JSON格式，请检查语法')
      }
    }
    
    // 添加参数
    const addParameter = () => {
      workflowParameters.value.push({
        name: '新参数',
        key: 'param' + (workflowParameters.value.length + 1),
        type: 'string',
        required: false,
        defaultValue: '',
        description: ''
      })
      
      // 更新JSON
      updateJsonFromWorkflow()
    }
    
    // 删除参数
    const removeParameter = (index) => {
      workflowParameters.value.splice(index, 1)
      
      // 更新JSON
      updateJsonFromWorkflow()
    }
    
    // 保存工作流
    const saveWorkflow = async () => {
      if (!settingsForm.value) return
      
      try {
        await settingsForm.value.validate()
        
        // 解析定义
        let definition = {}
        try {
          definition = JSON.parse(jsonDefinition.value)
        } catch (e) {
          ElMessage.error('工作流定义格式错误')
          return
        }
        
        // 创建工作流数据对象
        const workflowData = {
          name: workflow.name,
          description: workflow.description,
          workflow_type: workflow.workflow_type,
          is_public: workflow.is_public,
          tags: workflow.tags,
          definition: definition
        }
        
        if (isEdit.value) {
          workflowData.id = workflow.id
        }
        
        const savedWorkflow = await workflowStore.saveWorkflow(workflowData)
        ElMessage.success('工作流保存成功')
        
        // 如果是创建模式，保存后跳转到编辑模式
        if (!isEdit.value && savedWorkflow) {
          router.push(`/workflow/${savedWorkflow.id}/edit`)
        }
      } catch (error) {
        ElMessage.error('保存工作流失败: ' + (error.message || '未知错误'))
      }
    }
    
    // 获取默认节点名称
    const getDefaultNodeName = (type) => {
      const typeNames = {
        'a2a_client': 'A2A步骤',
        'condition': '条件步骤',
        'loop': '循环步骤',
        'transform': '转换步骤'
      }
      return typeNames[type] || '新步骤'
    }
    
    // 获取默认节点配置
    const getDefaultNodeConfig = (type) => {
      switch (type) {
        case 'a2a_client':
          return {
            agent_id: '',
            input_mapping: {},
            output_mapping: {},
            timeout: 300
          }
        case 'condition':
          return {
            condition: '',
            true_branch: [],
            false_branch: []
          }
        case 'loop':
          return {
            condition: '',
            max_iterations: 10,
            body: []
          }
        case 'transform':
          return {
            expression: '',
            output_var: 'result'
          }
        default:
          return {}
      }
    }
    
    // 获取工作流数据
    const fetchWorkflowData = async () => {
      if (!isEdit.value) return
      
      try {
        const id = route.params.id
        await workflowStore.fetchWorkflow(id)
        
        const currentWorkflow = workflowStore.currentWorkflow
        if (currentWorkflow) {
          // 填充工作流数据
          workflow.id = currentWorkflow.id
          workflow.name = currentWorkflow.name
          workflow.description = currentWorkflow.description
          workflow.workflow_type = currentWorkflow.workflow_type
          workflow.is_public = currentWorkflow.is_public
          workflow.tags = currentWorkflow.tags || []
          
          // 解析定义
          if (currentWorkflow.definition) {
            let definition = currentWorkflow.definition
            if (typeof definition === 'string') {
              try {
                definition = JSON.parse(definition)
              } catch (e) {
                definition = { steps: [] }
              }
            }
            
            workflow.steps = definition.steps || []
            
            // 设置参数
            if (definition.parameters && Array.isArray(definition.parameters)) {
              workflowParameters.value = definition.parameters.map(param => {
                // 对于对象类型，添加字符串表示
                if (param.type === 'object' && param.defaultValue) {
                  return {
                    ...param,
                    defaultValueStr: typeof param.defaultValue === 'string' 
                      ? param.defaultValue 
                      : JSON.stringify(param.defaultValue)
                  }
                }
                return param
              })
            }
            
            jsonDefinition.value = JSON.stringify(definition, null, 2)
          }
        }
      } catch (error) {
        ElMessage.error('获取工作流数据失败')
      }
    }
    
    // 初始化数据
    const initData = async () => {
      // 获取所有工作流以初始化标签下拉选项
      await workflowStore.fetchWorkflows()
      
      // 获取当前工作流数据（编辑模式）
      await fetchWorkflowData()
      
      if (!isEdit.value) {
        // 初始化空工作流的JSON
        updateJsonFromWorkflow()
      }
    }
    
    // 监听工作流steps的变化，更新JSON
    watch(() => [...workflow.steps], () => {
      updateJsonFromWorkflow()
    }, { deep: true })
    
    // 监听工作流参数的变化，更新JSON
    watch(() => workflowParameters.value, () => {
      updateJsonFromWorkflow()
    }, { deep: true })
    
    // 生命周期钩子
    onMounted(() => {
      initData()
    })
    
    return {
      workflow,
      activeTab,
      jsonDefinition,
      nodeEditVisible,
      currentNode,
      removeDialogVisible,
      settingsForm,
      settingsRules,
      isEdit,
      isLoading,
      workflowParameters,
      availableTags,
      updateFromJson,
      formatJson,
      addNode,
      editNode,
      saveNode,
      confirmRemoveNode,
      removeNode,
      moveNodeUp,
      moveNodeDown,
      saveWorkflow,
      addParameter,
      removeParameter,
      updateObjectDefault
    }
  }
}
</script>

